/**
 * Isolates the factorized-tail aggregation path on pure star joins: hubs fanning out over two predicates, aggregated
 * with COUNT variants whose tail matches are consumed as batches. Run twice — once as-is and once with
 * {@code -Drdf4j.lmdb.factorizedTail.enabled=false} — to compare against the enumerating baseline. Each invocation
 * verifies the expected count, so a wrong factorized result fails the run.
 */
@State(Scope.Benchmark)
@Warmup(iterations = 4, time = 2, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode({ Mode.AverageTime })
@Fork(value = 1, jvmArgs = { "-Xms1G", "-Xmx4G" })
@Measurement(iterations = 4, batchSize = 1, time = 2, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
public class FactorizedTailStarBenchmark {

	private static final String EX = "http://example.com/";
	private static final int HUBS = 1_000;
	private static final int P1_FANOUT = 10;
	private static final int P2_FANOUT = 100;
	private static final int P2_DISTINCT_VALUES = 500;

	@Param({
			"countHub",
			"countDistinctHub",
			"countTail",
			"countDistinctTail",
			"groupByTail"
	})
	public String variant;

	private java.io.File dataDir;
	private SailRepository repository;
	private String query;
	private long expected;

	@Setup(Level.Trial)
	public void setUp() {
		dataDir = Files.newTemporaryFolder();
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			conn.begin();
			for (int hub = 0; hub < HUBS; hub++) {
				IRI subject = vf.createIRI(EX, "hub" + hub);
				for (int i = 0; i < P1_FANOUT; i++) {
					conn.add(subject, p1, vf.createIRI(EX, "a" + (hub * P1_FANOUT + i)));
				}
				for (int i = 0; i < P2_FANOUT; i++) {
					conn.add(subject, p2, vf.createIRI(EX, "b" + ((hub * P2_FANOUT + i) % P2_DISTINCT_VALUES)));
				}
			}
			conn.commit();
		}
		long solutions = (long) HUBS * P1_FANOUT * P2_FANOUT;
		switch (variant) {
		case "countHub":
			query = star("(COUNT(?s) AS ?count)", "");
			expected = solutions;
			break;
		case "countDistinctHub":
			query = star("(COUNT(DISTINCT ?s) AS ?count)", "");
			expected = HUBS;
			break;
		case "countTail":
			query = star("(COUNT(?b) AS ?count)", "");
			expected = solutions;
			break;
		case "countDistinctTail":
			query = star("(COUNT(DISTINCT ?b) AS ?count)", "");
			expected = P2_DISTINCT_VALUES;
			break;
		case "groupByTail":
			query = star("?b (COUNT(?s) AS ?count)", "") + " GROUP BY ?b";
			// per group: (HUBS * P2_FANOUT / P2_DISTINCT_VALUES) hub-matches x P1_FANOUT
			expected = (long) HUBS * P2_FANOUT / P2_DISTINCT_VALUES * P1_FANOUT;
			break;
		default:
			throw new IllegalArgumentException(variant);
		}
	}

	private static String star(String select, String extra) {
		return "PREFIX ex: <" + EX + ">\n"
				+ "SELECT " + select + " WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ extra
				+ "}";
	}

	@TearDown(Level.Trial)
	public void tearDown() throws IOException {
		repository.shutDown();
		FileUtil.deleteDir(dataDir);
	}

	@Benchmark
	public long executeQuery() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			long total = 0;
			for (BindingSet bindings : result) {
				long count = ((Literal) bindings.getValue("count")).longValue();
				if (!"groupByTail".equals(variant) && count != expected) {
					throw new IllegalStateException(variant + ": expected " + expected + " but got " + count);
				}
				if ("groupByTail".equals(variant) && count != expected) {
					throw new IllegalStateException(variant + ": expected " + expected + " per group but got " + count);
				}
				total += count;
			}
			if ("groupByTail".equals(variant) && result.size() != P2_DISTINCT_VALUES) {
				throw new IllegalStateException("groupByTail: expected " + P2_DISTINCT_VALUES + " groups but got "
						+ result.size());
			}
			return total;
		}
	}

	public static void main(String[] args) throws RunnerException {
		Options opt = new OptionsBuilder()
				.include("FactorizedTailStarBenchmark")
				.build();
		new Runner(opt).run();
	}
}
